exercises.solution_code:
#include <iostream>
#include <string>

int main()
{
    int n{};
    std::cin >> n;
    std::cin.ignore();

    int sum{ 0 };

    for (int i{ 0 }; i < n; ++i)
    {
        std::string arg{};
        std::getline(std::cin, arg);
        sum += std::stoi(arg);
    }

    std::cout << "Sum: " << sum << '\n';

    return 0;
}
